var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"23:27 ARC-KP1\\n알파트릭스 본사 앞\\n<color=#ffd34c>사건 발생 약 30분 전</color>","JPN":"23:27 ARC-KP1\\nアルファトリックス本社前\\n<color=#ffd34c>事件発生約30分前</color>","ENG":"[[","TWN":"23:27 ARC-KP1\\n阿爾法崔克斯總公司前\\n<color=#ffd34c>事件發生前約30分鐘</color>","THA":"23.27 น. ARC-KP1\\nหน้าสาขาใหญ่ของอัลฟาทริกซ์\\n<color=#ffd34c>ประมาณ 30 นาทีก่อนเกิดเหตุ</color>","VTN":"23:27 ARC-KP1\\nPhía trước Tổng Bộ Alphatrix\\n <color=#ffd34c>Khoảng 30 phút trước sự cố</color>","SCN":"23:27 ARC-KP1\\n阿尔法崔克斯总公司门前\\n<color=#ffd34c>事件发生约30分钟前</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"이렇게 직접 얼굴 보는 건 오랜만이군, 이 실장.","JPN":"こうやって顔を合わせるのは久しぶりだな、シノザキ室長。","ENG":"It’s been a while since we last saw each other, hasn’t it, Chief?","TWN":"李室長，我們好久不見了。"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"여기서 오래 기다렸나?","JPN":"だいぶ待たせてしまったかな？","ENG":"Have you been waiting here for long?","TWN":"你在這裡等很久嗎？"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아닙니다. 부회장님.","JPN":"いいえ、副会長。","ENG":"Not at all, Vice Chairman.","TWN":"不會，副會長。"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그래. 차에 타게나. 집까지 데려다 주지.","JPN":"そうか、車に乗るといい。家まで送ろう。","ENG":"Good. Get in. I’ll take you home.","TWN":"上車吧，我載你回去。"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"괜찮네. 내 운전수는 입이 무거우니까.","JPN":"大丈夫だ、私の運転手は口が堅いから。","ENG":"Don’t worry. My driver is not one to talk to others about this.","TWN":"放心吧，我的司機嘴巴很牢靠。"},"stage":{"bg":"TEHERANRO_NIGHT","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"자네라면 내 거취에 대한 이야기는 이미 들었겠지.","JPN":"君なら私の去就について、すでに聞いているだろうな。","ENG":"I’m sure you already heard what’s going to happen to me.","TWN":"你應該有聽說我的事吧？"},"stage":{"bg":"CAR","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……예. 이사진들이 그간 칼을 갈고 있었더군요.","JPN":"……はい、理事たちが用意周到に計画を練っていたそうですね。","ENG":"...Yes. I heard the board has been planning this for a long time now.","TWN":"……有，這段時間董事們一直在伺機而動。"},"stage":{"bg":"CAR","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그래. 소식을 듣고 나도 이제 할 만큼 했나 싶더군.","JPN":"ああ。それを聞いて私もそろそろ潮時かと思ったよ。","ENG":"Yes. After hearing the news, I thought it was the end of the line for me.","TWN":"嗯嗯，我聽到消息後在想，我是否已經做完我該做的。"},"stage":{"bg":"CAR","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그 늙은 너구리들에게 뒤통수를 맞는 날이 올 줄이야.","JPN":"あの老いぼれタヌキどもに裏切られる日が来るとは。","ENG":"Who knew those dusty baboons would stab me in the back like that.","TWN":"沒想到會被那些老狐狸給擺一道！"},"stage":{"bg":"CAR","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"하긴…… 권한대행이라는 핑계로 너무 오랫동안 회장 자리를 비워두긴 했어.","JPN":"まあ……権限代行に留まって、長らく会長職を空席のままにしていたからな。","ENG":"But then again, we did leave the seat vacant for far too long under the guise of having an acting Chairman.","TWN":"也是……畢竟假借代理職務的名義，會長的位置已經閒置許久。"},"stage":{"bg":"CAR","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"아니, 사실은 그저 회장 자리에 앉기 두려웠던 거겠지.","JPN":"いや、本当は会長の座に就くのが怖かったのだろう。","ENG":"Truth be told, I was afraid of actually becoming <color=#ffd34c>President</color>.","TWN":"不，其實是我害怕坐上會長的位置。"},"stage":{"bg":"CAR","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"아버지는 집안에선 망할 쓰레기였지만 회사에선 사업의 신이나 마찬가지였으니까.","JPN":"父は家庭では救いようのないクズ野郎だったが、\\n会社では仕事の神のような存在だったからな。","ENG":"Even though Father was regarded as trash by his family, he was regarded as a god at work.","TWN":"雖然爸在家裡是無可救藥的垃圾，但他在公司裡的地位跟神一樣。"},"stage":{"bg":"CAR","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"회장 자리에 앉아서 그 양반보다 못하다고 비교당하는 건……. 상상만으로도 끔찍해.","JPN":"会長になって、父と比べて無能だと言われるのは……\\n想像するだけでゾッとする。","ENG":"Being President and constantly being compared to him... Even imagining it is terrifying.","TWN":"我怕我當上會長後，大家覺得我做得比他差勁……光想就覺得可怕。"},"stage":{"bg":"CAR","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAR","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"자네 머리 굴리는 소리가 여기까지 들리는군.","JPN":"君が言葉を探して頭を回しているのがひしひしと伝わるな。","ENG":"I can see you’re trying to figure out why I wanted to see you.","TWN":"你心裡是這麼想的吧？"},"stage":{"bg":"CAR","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};